SELECT COUNT(DISTINCT LPB.FK_PRODBIB) AS TOTAL_PRODUCOES FROM LATTES_P_PRODBIB LPB JOIN SERVIDOR S ON LPB.FK_SIAPE = S.PK_SIAPE JOIN LATTES_PRODBIB PB ON LPB.FK_PRODBIB = PB.PK WHERE LOWER(S.CAMPUS_ATUAL) LIKE LOWER('%goiania%') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%turismo%') AND S.GENERO = 'FEMININO' AND LOWER(PB.TIPO) LIKE LOWER('%ARTIGO%') AND LOWER(PB.NATUREZA) LIKE LOWER('%completo%') AND PB.ANO = '2022'